CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY, email TEXT UNIQUE NOT NULL, nama TEXT NOT NULL, phone TEXT, password TEXT NOT NULL, role TEXT NOT NULL DEFAULT 'user' CHECK(role IN ('user','admin')), saldo INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL DEFAULT (datetime('now','+7 hours')));
CREATE INDEX IF NOT EXISTS idx_users_email ON users(email);
CREATE TABLE IF NOT EXISTS transactions (id TEXT PRIMARY KEY, user_id TEXT NOT NULL, customer_no TEXT NOT NULL, product_code TEXT NOT NULL, product_name TEXT, kategori TEXT, harga INTEGER NOT NULL, status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','processing','success','failed','refund')), sn TEXT, message TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now','+7 hours')), FOREIGN KEY (user_id) REFERENCES users(id));
CREATE INDEX IF NOT EXISTS idx_transactions_user ON transactions(user_id);
CREATE TABLE IF NOT EXISTS topups (id TEXT PRIMARY KEY, user_id TEXT NOT NULL, amount INTEGER NOT NULL, fee INTEGER DEFAULT 0, total INTEGER NOT NULL, payment_method TEXT, payment_channel TEXT, status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','paid','expired','cancelled')), va_number TEXT, qr_url TEXT, expired_at TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now','+7 hours')), FOREIGN KEY (user_id) REFERENCES users(id));
